sql:
SELECT date, total_deaths
FROM cumulative_stats
ORDER BY date DESC;

SELECT date, D
FROM daily_reports
ORDER BY date DESC;

SELECT date
FROM daily_reports
ORDER BY date;

SELECT total_infections, total_tests, total_deaths
FROM cumulative_stats
WHERE date = '2023-10-01';

SELECT SUM(tests_conducted) AS total_tests_conducted
FROM testing_reports
WHERE center_id = 1;

SELECT SUM(hr.hospitalizations) AS total_hospitalizations
FROM hospital_reports hr
JOIN daily_reports dr ON hr.report_id = dr.report_id
WHERE dr.date = (
    SELECT MAX(date) FROM daily_reports
);

external_knowledge:
- The time period of interest is the year 2023; 
- The threshold for considering a hospital is more than 100 patients; 
- Another condition is that the total infections in the location should exceed 1000 on the most recent date available.

